+    let mode = if force_line {
+        VisualSelectionMode::Line
+    } else {
+        selection.mode
+    };
+
+    match mode {
+        VisualSelectionMode::Line => {
+            for line_index in start_line..=end_line {
+                ranges[line_index] = Some((0, lines[line_index].chars().count()));
+            }
+        }
+        VisualSelectionMode::Block => {
+            let start_column = selection.anchor.column.min(selection.cursor.column);
+            let end_column = selection.anchor.column.max(selection.cursor.column);
+            for line_index in start_line..=end_line {
+                let line_len = lines[line_index].chars().count();
+                let start = start_column.min(line_len);
+                let end = end_column.saturating_add(1).min(line_len);
+                ranges[line_index] = Some((start, end));
+            }
+        }
+        VisualSelectionMode::Character => {
+            let (start, end) = ordered_cursors(selection.anchor, selection.cursor);
+            let start_line = start.line.min(lines.len() - 1);
+            let end_line = end.line.min(lines.len() - 1);
+            if start_line == end_line {
+                let line_len = lines[start_line].chars().count();
+                ranges[start_line] = Some((
+                    start.column.min(line_len),
+                    end.column.saturating_add(1).min(line_len),
+                ));
+            } else {
+                for line_index in start_line..=end_line {
+                    let line_len = lines[line_index].chars().count();
+                    ranges[line_index] = if line_index == start_line {
+                        Some((start.column.min(line_len), line_len))
+                    } else if line_index == end_line {
+                        Some((0, end.column.saturating_add(1).min(line_len)))
+                    } else {
+                        Some((0, line_len))
+                    };
+                }
+            }
+        }
+    }
