 81	    pub fn handle_bytes(&mut self, bytes: &[u8]) -> bool {
 82	        let mut index = 0;
 83	        while index < bytes.len() {
 84	            if let Some((key, len)) = parse_key_sequence(&bytes[index..]) {
 85	                self.handle_input(HarnessInput::Key(key));
 86	                index += len;
 87	            } else if !self.handle_byte(bytes[index]) {
 88	                return false;
 89	            } else {
 90	                index += 1;
 91	            }
 92	        }
 93	        self.finish_pending_escape_sequence();
 94	        !self.quit
 95	    }
 96	
 97	    pub fn handle_byte(&mut self, byte: u8) -> bool {
 98	        if self.quit {
 99	            return false;
100	        }
101	
102	        if self.continue_escape_sequence(byte) {
103	            return !self.quit;
104	        }
105	
106	        if byte == 27 {
107	            let defer_escape = self.defer_escape_key();
108	            self.escape_sequence = Some(PendingEscapeSequence {
109	                bytes: vec![27],
110	                mode_before: self.ui.mode(),
111	                escape_dispatched: !defer_escape,
112	            });
113	            if !defer_escape {
114	                self.handle_input(HarnessInput::Key(UiKey::Esc));
115	            }
116	            return !self.quit;
117	        }
118	
119	        let Some(input) = HarnessInput::from_byte(byte) else {
120	            return true;
121	        };
122	        self.handle_input(input);
123	        !self.quit
124	    }
125	
126	    pub fn render_frame(&self) -> String {
127	        self.ui.render_screen_with_cursors(
128	            &self.right_content(),
129	            &self.prompt_buffer,
130	            self.prompt_cursor,
131	            Some(self.chat_cursor_column()),
132	        )
133	    }
134	
135	    fn handle_input(&mut self, input: HarnessInput) {
136	        match input {
137	            HarnessInput::Quit => self.quit = true,
138	            HarnessInput::Interrupt => {
139	                self.ui.show_ctrl_c_exit_notice();
140	                if self.ui.focus() == PaneFocus::Right
141	                    && let Some(agent_id) = self.ui.selected_agent()
142	                {
143	                    self.transcript
144	                        .push(format!("work-leaf: sent Ctrl-C to {agent_id}"));
145	                }
146	            }
147	            HarnessInput::Backspace if self.ui.mode() == UiMode::Prompt => {
148	                self.backspace_prompt_char();
149	            }
150	            HarnessInput::Backspace if self.ui.mode() == UiMode::Insert => {
151	                self.backspace_chat_char();
152	            }
153	            HarnessInput::Enter if self.ui.mode() == UiMode::Prompt => {
154	                let line = self.prompt_buffer.trim().to_string();
155	                self.prompt_buffer.clear();
156	                self.prompt_cursor = 0;
157	                self.prompt_history_index = None;
158	                self.prompt_history_draft = None;
159	                let actions = self.handle_ui_key(UiKey::Esc);
160	                self.record_actions(actions);
161	                if !line.is_empty() {
162	                    self.prompt_history.push(line.clone());
163	                    self.transcript.push(format!("work-leaf> {line}"));
164	                    self.execute_prompt(&line);
165	                }
166	            }
167	            HarnessInput::Enter if self.ui.mode() == UiMode::Insert => {
168	                let message = self.chat_buffer.trim().to_string();
169	                self.chat_buffer.clear();
170	                self.chat_cursor = 0;
171	                self.chat_history_index = None;
172	                self.chat_history_draft = None;
173	                if !message.is_empty() {
174	                    self.chat_history.push(message.clone());
175	                    let target_agent = self.ui.selected_agent().cloned();
176	                    if let Some(agent_id) = target_agent.as_ref() {
177	                        self.name_chat_from_first_prompt(agent_id, &message);
178	                    }
179	                    let target = target_agent
