392	    fn handle_key_inner(&mut self, key: UiKey, right_content: &str) -> Vec<UiAction> {
393	        match key {
394	            UiKey::MouseClick { column, row } => {
395	                self.pending = None;
396	                self.clear_visual_selection();
397	                return self.handle_mouse_click(column, row);
398	            }
399	            UiKey::MouseScrollUp { column, row } => {
400	                self.pending = None;
401	                self.handle_mouse_scroll(column, row, true);
402	                return Vec::new();
403	            }
404	            UiKey::MouseScrollDown { column, row } => {
405	                self.pending = None;
406	                self.handle_mouse_scroll(column, row, false);
407	                return Vec::new();
408	            }
409	            _ => {}
410	        }
411	
412	        if self.visual_selection.is_some() {
413	            return self.handle_visual_key(key, right_content);
414	        }
415	
416	        if let Some(pending) = self.pending.take() {
417	            return self.handle_pending_key(pending, key);
418	        }
419	
420	        match key {
421	            UiKey::Esc => {
422	                self.mode = UiMode::Command;
423	                self.clear_visual_selection();
424	                Vec::new()
425	            }
426	            UiKey::CtrlW if self.mode == UiMode::Command => {
427	                self.pending = Some(PendingKey::CtrlW);
428	                Vec::new()
429	            }
430	            UiKey::Char('g') if self.mode == UiMode::Command => {
431	                self.pending = Some(PendingKey::G);
432	                Vec::new()
433	            }
434	            UiKey::Char('i') if self.mode == UiMode::Command => {
435	                self.mode = UiMode::Insert;
436	                self.clear_visual_selection();
437	                Vec::new()
438	            }
439	            UiKey::Char(':') if self.mode == UiMode::Command => {
440	                self.mode = UiMode::Prompt;
441	                self.clear_visual_selection();
442	                Vec::new()
443	            }
444	            UiKey::Char('v') if self.mode == UiMode::Command => {
445	                self.begin_visual_selection(VisualSelectionMode::Character, right_content);
446	                Vec::new()
447	            }
448	            UiKey::Char('V') if self.mode == UiMode::Command => {
449	                self.begin_visual_selection(VisualSelectionMode::Line, right_content);
450	                Vec::new()
451	            }
452	            UiKey::Char(VISUAL_BLOCK_CONTROL) if self.mode == UiMode::Command => {
453	                self.begin_visual_selection(VisualSelectionMode::Block, right_content);
454	                Vec::new()
455	            }
456	            UiKey::Char(',') if self.mode == UiMode::Command => {
457	                self.clear_visual_selection();
458	                self.left_visible = !self.left_visible;
459	                self.focus = if self.left_visible {
460	                    PaneFocus::Left
461	                } else {
462	                    PaneFocus::Right
463	                };
464	                Vec::new()
465	            }
466	            UiKey::Char('j') if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
467	                self.move_control_selection(1);
468	                self.select_control_row_surface();
469	                Vec::new()
470	            }
471	            UiKey::Down if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
472	                self.move_control_selection(1);
473	                self.select_control_row_surface();
474	                Vec::new()
475	            }
476	            UiKey::Right if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
477	                self.move_control_selection(1);
478	                self.select_control_row_surface();
479	                Vec::new()
480	            }
481	            UiKey::Char('k') if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
482	                self.move_control_selection(-1);
483	                self.select_control_row_surface();
484	                Vec::new()
485	            }
486	            UiKey::Up if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
487	                self.move_control_selection(-1);
488	                self.select_control_row_surface();
489	                Vec::new()
490	            }
491	            UiKey::Left if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
492	                self.move_control_selection(-1);
493	                self.select_control_row_surface();
494	                Vec::new()
495	            }
496	            UiKey::Char('l') if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
497	                self.open_control_selection();
498	                Vec::new()
499	            }
500	            UiKey::Char('x') if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
501	                self.hide_control_selection();
502	                Vec::new()
503	            }
504	            UiKey::Char('s') if self.mode == UiMode::Command => self.open_selected_same_pane(),
505	            UiKey::Char('t') if self.mode == UiMode::Command => self.open_selected_new_window(),
506	            UiKey::Char('f') if self.mode == UiMode::Command => self.fork_selected_agent(),
507	            _ => Vec::new(),
508	        }
509	    }
