511	    fn handle_visual_key(&mut self, key: UiKey, right_content: &str) -> Vec<UiAction> {
512	        match key {
513	            UiKey::Esc => {
514	                self.clear_visual_selection();
515	            }
516	            UiKey::Char('v') => {
517	                self.switch_visual_selection_mode(VisualSelectionMode::Character, right_content);
518	            }
519	            UiKey::Char('V') => {
520	                self.switch_visual_selection_mode(VisualSelectionMode::Line, right_content);
521	            }
522	            UiKey::Char(VISUAL_BLOCK_CONTROL) => {
523	                self.switch_visual_selection_mode(VisualSelectionMode::Block, right_content);
524	            }
525	            UiKey::Char('h') | UiKey::Left => {
526	                self.move_visual_cursor(0, -1, right_content);
527	            }
528	            UiKey::Char('l') | UiKey::Right => {
529	                self.move_visual_cursor(0, 1, right_content);
530	            }
531	            UiKey::Char('k') | UiKey::Up => {
532	                self.move_visual_cursor(-1, 0, right_content);
533	            }
534	            UiKey::Char('j') | UiKey::Down => {
535	                self.move_visual_cursor(1, 0, right_content);
536	            }
537	            UiKey::Char('y') => {
538	                self.yank_visual_selection(right_content, false);
539	            }
540	            UiKey::Char('Y') => {
541	                self.yank_visual_selection(right_content, true);
542	            }
543	            _ => {}
544	        }
545	        Vec::new()
546	    }
