602	        let lines = self.selection_lines(selection.focus, right_content);
603	        let text = selected_text(&lines, &selection, force_line);
604	        let char_count = text.chars().count();
605	        self.pending_yank = Some(text);
606	        self.clear_visual_selection();
607	        self.show_status_notice(
608	            format!("work-leaf: copied {char_count} chars"),
609	            Duration::from_secs(STATUS_NOTICE_SECONDS),
610	        );
611	    }
