670	            rendered.push_str("> work-leaf  command\n");
671	        } else {
672	            rendered.push_str("  work-leaf  command\n");
673	        }
674	        for (visible_position, agent_index) in self.visible_agent_indices().iter().enumerate() {
675	            let agent = &self.agents[*agent_index];
676	            let mut row = String::new();
677	            row.push(if self.control_selected == visible_position + 1 {
678	                '>'
679	            } else {
680	                ' '
