682	            let (primary, secondary) = agent_list_labels(agent);
683	            row.push_str(primary);
684	            row.push(' ');
685	            row.push_str(secondary);
686	            row.push_str("  working: ");
687	            row.push_str(&agent.feature);
688	            if agent.ready {
689	                row.push_str("  READY");
690	                rendered.push_str("\u{1b}[7m");
691	                rendered.push_str(&row);
692	                rendered.push_str("\u{1b}[0m");
693	            } else {
694	                rendered.push_str(&row);
695	            }
696	            rendered.push('\n');
697	            if !agent.modified_files.is_empty() {
698	                rendered.push_str("    ");
699	                rendered.push_str("files: ");
700	                rendered.push_str(
