702	                        .modified_files
703	                        .iter()
704	                        .map(|path| path.display().to_string())
705	                        .collect::<Vec<_>>()
706	                        .join(", "),
707	                );
708	                rendered.push('\n');
709	            }
710	            self.render_agent_links("conflicts", &agent.conflicting_agents, &mut rendered);
711	            self.render_agent_links("depends-on", &agent.depends_on, &mut rendered);
712	            self.render_agent_links("depended-on-by", &agent.depended_on_by, &mut rendered);
713	        }
