1314	    fn right_cursor_position_with_cursor(
1315	        &self,
1316	        right_content: &str,
1317	        cursor_column: Option<usize>,
1318	    ) -> (u16, u16) {
1319	        let layout = self.layout();
1320	        let inner_width = layout.right_width.saturating_sub(2).max(1);
1321	        let lines = right_content.lines().collect::<Vec<_>>();
1322	        let Some(line) = lines.last().copied() else {
1323	            return (2, layout.left_width.saturating_add(2));
1324	        };
1325	        if !line.starts_with("chat> ") {
1326	            return (2, layout.left_width.saturating_add(2));
1327	        }
1328	        let previous_rows = lines[..lines.len() - 1]
1329	            .iter()
1330	            .map(|line| visual_rows(line, inner_width))
1331	            .sum::<u16>();
1332	        let line_chars = line.chars().count();
1333	        let line_len = cursor_column
1334	            .unwrap_or(line_chars)
1335	            .min(line_chars)
1336	            .min(usize::from(u16::MAX)) as u16;
1337	        let row = 2_u16
1338	            .saturating_add(previous_rows)
1339	            .saturating_add(line_len / inner_width);
1340	        let column = layout
1341	            .left_width
1342	            .saturating_add(2)
1343	            .saturating_add(line_len % inner_width);
1344	        (row, column)
1345	    }
