1572	fn slice_chars(text: &str, start: usize, end: usize) -> String {
1573	    let start = start.min(text.chars().count());
1574	    let end = end.min(text.chars().count());
1575	    text.chars()
1576	        .skip(start)
1577	        .take(end.saturating_sub(start))
1578	        .collect()
1579	}
