 972	    fn continue_escape_sequence(&mut self, byte: u8) -> bool {
 973	        let Some(sequence) = self.escape_sequence.as_mut() else {
 974	            return false;
 975	        };
 976	
 977	        if sequence.bytes.is_empty() && byte != b'[' {
 978	            let sequence = self
 979	                .escape_sequence
 980	                .take()
 981	                .expect("escape sequence is present");
 982	            self.dispatch_pending_escape_if_needed(&sequence);
 983	            return false;
 984	        }
 985	
 986	        sequence.bytes.push(byte);
 987	        if is_complete_control_sequence(&sequence.bytes) {
 988	            let sequence = self
 989	                .escape_sequence
 990	                .take()
 991	                .expect("escape sequence is present");
 992	            if sequence.escape_dispatched
 993	                && sequence.mode_before == UiMode::Insert
 994	                && self.ui.mode() != UiMode::Insert
 995	            {
 996	                let actions = self.handle_ui_key(UiKey::Char('i'));
 997	                self.record_actions(actions);
 998	            }
 999	            if let Some(input) = parse_control_sequence(&sequence.bytes) {
1000	                self.handle_input(input);
1001	            }
1002	        } else if sequence.bytes.len() > MAX_ESCAPE_SEQUENCE {
1003	            let sequence = self
1004	                .escape_sequence
1005	                .take()
1006	                .expect("escape sequence is present");
1007	            self.dispatch_pending_escape_if_needed(&sequence);
1008	        }
1009	
1010	        true
1011	    }
