1035	fn parse_control_sequence(sequence: &[u8]) -> Option<TerminalAppInput> {
1036	    match sequence {
1037	        [b'[', b'A'] => Some(TerminalAppInput::Key(UiKey::Up)),
1038	        [b'[', b'B'] => Some(TerminalAppInput::Key(UiKey::Down)),
1039	        [b'[', b'C'] => Some(TerminalAppInput::Key(UiKey::Right)),
1040	        [b'[', b'D'] => Some(TerminalAppInput::Key(UiKey::Left)),
1041	        [b'[', b'2', b'0', b'0', b'~'] => Some(TerminalAppInput::PasteStart),
1042	        [b'[', b'2', b'0', b'1', b'~'] => Some(TerminalAppInput::PasteEnd),
1043	        [b'[', b'1', b'3', b';', b'2', b'u']
1044	        | [b'[', b'1', b'3', b';', b'2', b'~']
1045	        | [b'[', b'2', b'7', b';', b'2', b';', b'1', b'3', b'~'] => {
1046	            Some(TerminalAppInput::LineBreak)
1047	        }
1048	        _ => parse_sgr_mouse_event(sequence).map(TerminalAppInput::Key),
1049	    }
1050	}
1051	
1052	fn parse_sgr_mouse_event(sequence: &[u8]) -> Option<UiKey> {
1053	    let final_byte = *sequence.last()?;
1054	    if !sequence.starts_with(b"[<") || !matches!(final_byte, b'M' | b'm') {
1055	        return None;
1056	    }
1057	
1058	    let body = std::str::from_utf8(&sequence[2..sequence.len() - 1]).ok()?;
1059	    let mut parts = body.split(';');
1060	    let button = parts.next()?.parse::<u16>().ok()?;
1061	    let column = parts.next()?.parse::<u16>().ok()?;
1062	    let row = parts.next()?.parse::<u16>().ok()?;
1063	    if parts.next().is_some() {
1064	        return None;
1065	    }
1066	
1067	    let button_kind = button & !0b0001_1100_u16;
1068	    match (button_kind, final_byte) {
1069	        (64, b'M') => Some(UiKey::MouseScrollUp { column, row }),
1070	        (65, b'M') => Some(UiKey::MouseScrollDown { column, row }),
1071	        (_, b'M' | b'm') if button_kind < 64 && button & 0b11 == 0 => {
1072	            Some(UiKey::MouseClick { column, row })
1073	        }
1074	        _ => None,
1075	    }
1076	}
