1188	fn base64_standard(bytes: &[u8]) -> String {
1189	    const TABLE: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
1190	    let mut encoded = String::with_capacity(bytes.len().div_ceil(3) * 4);
1191	    for chunk in bytes.chunks(3) {
1192	        let first = chunk[0];
1193	        let second = chunk.get(1).copied().unwrap_or(0);
1194	        let third = chunk.get(2).copied().unwrap_or(0);
1195	
1196	        encoded.push(TABLE[(first >> 2) as usize] as char);
1197	        encoded.push(TABLE[(((first & 0b0000_0011) << 4) | (second >> 4)) as usize] as char);
1198	        if chunk.len() > 1 {
1199	            encoded.push(TABLE[(((second & 0b0000_1111) << 2) | (third >> 6)) as usize] as char);
1200	        } else {
1201	            encoded.push('=');
1202	        }
1203	        if chunk.len() > 2 {
1204	            encoded.push(TABLE[(third & 0b0011_1111) as usize] as char);
1205	        } else {
1206	            encoded.push('=');
1207	        }
1208	    }
1209	    encoded
1210	}
