 945	    fn prompt_view(&self, prompt: &str, prompt_cursor: usize) -> PromptView {
 946	        let width = usize::from(self.width.max(1));
 947	        let input_width = width.saturating_sub(1);
 948	        let max_cursor_offset = width.saturating_sub(2);
 949	        let cursor_chars = cursor_char_count(prompt, prompt_cursor);
 950	        let start = cursor_chars.saturating_sub(max_cursor_offset);
 951	        let visible_prompt = prompt
 952	            .chars()
 953	            .skip(start)
 954	            .take(input_width)
 955	            .collect::<String>();
 956	        let cursor_offset = cursor_chars.saturating_sub(start).min(max_cursor_offset);
 957	        let cursor_column = if self.width <= 1 {
 958	            1
 959	        } else {
 960	            cursor_offset.saturating_add(2).min(width) as u16
 961	        };
 962	        PromptView {
 963	            line: format!(":{visible_prompt}"),
 964	            cursor_column,
 965	        }
 966	    }
