550	fn parse_key_sequence(bytes: &[u8]) -> Option<(UiKey, usize)> {
551	    match bytes {
552	        [27, b'[', b'A', ..] => Some((UiKey::Up, 3)),
553	        [27, b'[', b'B', ..] => Some((UiKey::Down, 3)),
554	        [27, b'[', b'C', ..] => Some((UiKey::Right, 3)),
555	        [27, b'[', b'D', ..] => Some((UiKey::Left, 3)),
556	        _ => parse_sgr_mouse_sequence(bytes),
557	    }
558	}
559	
560	fn parse_sgr_mouse_sequence(bytes: &[u8]) -> Option<(UiKey, usize)> {
561	    if !bytes.starts_with(b"\x1b[<") {
562	        return None;
563	    }
564	
565	    let final_index = bytes.iter().position(|byte| matches!(byte, b'M' | b'm'))?;
566	    let final_byte = bytes[final_index];
567	    let body = std::str::from_utf8(&bytes[3..final_index]).ok()?;
568	    let mut parts = body.split(';');
569	    let button = parts.next()?.parse::<u16>().ok()?;
570	    let column = parts.next()?.parse::<u16>().ok()?;
571	    let row = parts.next()?.parse::<u16>().ok()?;
572	    if parts.next().is_some() {
573	        return None;
574	    }
575	
576	    let button_kind = button & !0b0001_1100_u16;
577	    let key = match (button_kind, final_byte) {
578	        (64, b'M') => UiKey::MouseScrollUp { column, row },
579	        (65, b'M') => UiKey::MouseScrollDown { column, row },
580	        (_, b'M' | b'm') if button_kind < 64 && button & 0b11 == 0 => {
581	            UiKey::MouseClick { column, row }
582	        }
583	        _ => return None,
584	    };
585	    Some((key, final_index + 1))
586	}
