 39	pub fn parse_process_args<I, S>(args: I) -> Result<ProcessCommand, CliError>
 40	where
 41	    I: IntoIterator<Item = S>,
 42	    S: Into<String>,
 43	{
 44	    let mut args = args.into_iter().map(Into::into).collect::<Vec<_>>();
 45	    if args.first().is_some_and(|arg| arg.ends_with("work-leaf")) {
 46	        args.remove(0);
 47	    }
 48	
 49	    if args.is_empty() {
 50	        return Ok(ProcessCommand::Launch {
 51	            model: None,
 52	            read_permission: ReadPermission::Orchestrator,
 53	        });
 54	    }
 55	
 56	    let mut model = None;
 57	    let mut read_permission = ReadPermission::Orchestrator;
 58	    let mut index = 0;
 59	    while index < args.len() {
 60	        match args[index].as_str() {
 61	            "--help" | "-h" | "help" => return Ok(ProcessCommand::Help),
 62	            "--no-read-permission" => {
 63	                read_permission = ReadPermission::DirectFilesystem;
 64	                index += 1;
 65	            }
 66	            "--model" => {
 67	                if index + 1 >= args.len() {
 68	                    return Err(CliError::Usage("--model requires a value".to_string()));
 69	                }
 70	                model = Some(args[index + 1].clone());
 71	                index += 2;
 72	            }
 73	            "new" | "patch" | "review" | "linearize" | "linearize-questions" | "locks" => {
 74	                return Err(CliError::Usage(
 75	                    "work-leaf does not accept top-level workflow commands; start work-leaf and use the command chat".to_string(),
 76	                ));
 77	            }
 78	            other => return Err(CliError::Usage(format!("unknown option `{other}`"))),
 79	        }
 80	    }
 81	
 82	    Ok(ProcessCommand::Launch {
 83	        model,
 84	        read_permission,
 85	    })
 86	}
