 88	pub fn run_cli_from_env() -> ! {
 89	    let command = match parse_process_args(env::args()) {
 90	        Ok(command) => command,
 91	        Err(error) => {
 92	            eprintln!("{error}");
 93	            process::exit(2);
 94	        }
 95	    };
 96	
 97	    match command {
 98	        ProcessCommand::Help => {
 99	            print!("{}", render_process_help());
100	            process::exit(0);
101	        }
102	        ProcessCommand::Launch {
103	            model,
104	            read_permission,
105	        } => {
106	            let result = if env::var_os("WORK_LEAF_IN_PROCESS").is_some() {
107	                run_in_process_cli(model, read_permission)
108	            } else {
109	                run_http_cli(model, read_permission)
110	            };
111	            if let Err(error) = result {
112	                eprintln!("{error}");
113	                process::exit(1);
114	            }
115	            process::exit(0);
116	        }
117	    }
118	}
