1134	struct PrintedRemoteState {
1135	    command_lines: usize,
1136	    session_lines: BTreeMap<AgentId, usize>,
1137	}
1138	
1139	impl PrintedRemoteState {
1140	    fn new(snapshot: WorkLeafSnapshot) -> Self {
1141	        Self {
1142	            command_lines: snapshot.command_transcript.len(),
1143	            session_lines: snapshot
1144	                .sessions
1145	                .into_iter()
1146	                .map(|session| (session.id, session.lines.len()))
1147	                .collect(),
1148	        }
1149	    }
1150	
1151	    fn print_new_lines(
1152	        &mut self,
1153	        snapshot: WorkLeafSnapshot,
1154	        output: &mut impl Write,
1155	    ) -> Result<(), CliError> {
1156	        for line in snapshot.command_transcript.iter().skip(self.command_lines) {
1157	            writeln!(output, "{line}")?;
1158	        }
1159	        self.command_lines = snapshot.command_transcript.len();
1160	
1161	        for session in snapshot.sessions {
1162	            let printed = self.session_lines.entry(session.id.clone()).or_insert(0);
1163	            for line in session.lines.iter().skip(*printed) {
1164	                writeln!(output, "{line}")?;
1165	            }
1166	            *printed = session.lines.len();
1167	        }
1168	        output.flush()?;
1169	        Ok(())
1170	    }
1171	}
1172	
1173	fn wait_and_print_remote_updates(
1174	    client: &mut HttpControllerClient,
1175	    printed: &mut PrintedRemoteState,
1176	    output: &mut impl Write,
1177	) -> Result<(), CliError> {
1178	    loop {
1179	        let busy = client.is_busy().map_err(http_cli_error)?;
1180	        let snapshot = client.snapshot().map_err(http_cli_error)?;
1181	        printed.print_new_lines(snapshot, output)?;
1182	        if !busy {
1183	            break;
1184	        }
1185	        thread::sleep(Duration::from_millis(20));
1186	    }
1187	    Ok(())
1188	}
