133	    fn spawn(project_dir: &Path, fake_bin: &Path, width: u16, height: u16) -> Self {
134	        let (master, slave) = open_pty(width, height);
135	        let master_file = unsafe { File::from_raw_fd(master) };
136	        let mut slave_file = unsafe { File::from_raw_fd(slave) };
137	        let stdin = Stdio::from(slave_file.try_clone().unwrap());
138	        let stdout = Stdio::from(slave_file.try_clone().unwrap());
139	        let stderr = Stdio::from(slave_file.try_clone().unwrap());
140	        let path = format!(
141	            "{}:{}",
142	            fake_bin.display(),
143	            std::env::var("PATH").unwrap_or_default()
144	        );
145	        let child = Command::new(env!("CARGO_BIN_EXE_work-leaf"))
146	            .current_dir(project_dir)
147	            .env("PATH", path)
148	            .stdin(stdin)
149	            .stdout(stdout)
150	            .stderr(stderr)
151	            .spawn()
152	            .unwrap();
153	        let _ = slave_file.flush();
154	        drop(slave_file);
155	
156	        let transcript = Arc::new(Mutex::new(String::new()));
157	        let reader_transcript = Arc::clone(&transcript);
158	        let mut reader_file = master_file.try_clone().unwrap();
159	        let reader = thread::spawn(move || {
160	            let mut buffer = [0_u8; 4096];
161	            loop {
162	                match reader_file.read(&mut buffer) {
163	                    Ok(0) => break,
164	                    Ok(count) => {
165	                        let text = String::from_utf8_lossy(&buffer[..count]);
166	                        reader_transcript.lock().unwrap().push_str(&text);
167	                    }
168	                    Err(error) if error.kind() == ErrorKind::Interrupted => {}
169	                    Err(_) => break,
170	                }
171	            }
172	        });
173	
174	        Self {
175	            child,
176	            writer: master_file,
177	            transcript,
178	            reader: Some(reader),
179	        }
180	    }
