202	    fn wait_for<F>(&self, timeout: Duration, predicate: F, expected: &str)
203	    where
204	        F: Fn(&str) -> bool,
205	    {
206	        let start = Instant::now();
207	        loop {
208	            let output = self.output();
209	            if predicate(&output) {
210	                return;
211	            }
212	            assert!(
213	                start.elapsed() < timeout,
214	                "timed out waiting for {expected}\nlast frame:\n{}",
215	                last_frame(&output)
216	            );
217	            thread::sleep(Duration::from_millis(20));
218	        }
219	    }
