227	    fn drop(&mut self) {
228	        let _ = self.writer.write_all(&[3]);
229	        let _ = self.writer.flush();
230	        let start = Instant::now();
231	        while start.elapsed() < Duration::from_secs(2) {
232	            if self.child.try_wait().ok().flatten().is_some() {
233	                break;
234	            }
235	            thread::sleep(Duration::from_millis(20));
236	        }
237	        if self.child.try_wait().ok().flatten().is_none() {
238	            let _ = self.child.kill();
239	        }
240	        let _ = self.child.wait();
241	        if let Some(reader) = self.reader.take() {
242	            let _ = reader.join();
243	        }
244	    }
245	}
